const $ = new Env("网际快车签到");

let userCookie = process.env.WJ_KC_COOKIE;
let userCount = 0;
let userList = [];
let userIdx = 0;

class UserInfo {
  constructor(options) {
    this.index = ++userIdx;
    this.username = options.username;
    this.password = options.password;
  }
  async sign() {
    try {
      // 任务数据
      const taskData = {
        // 配置账号密码实现登录
        steps: [
          {
            type: "goto",
            name: "跳转到登录页",
            url: "https://wj-kc.com/#/login",
            delay: 2000,
          },
          {
            type: "waitForSelector",
            name: "等待输入邮箱输入框显示",
            selector: "#email",
          },
          {
            type: "input",
            name: "输入账号",
            selector: "#email",
            value: this.username,
            delay: 2000,
          },
          {
            type: "input",
            name: "输入密码",
            selector: "#password",
            value: this.password,
            delay: 2000,
          },
          { type: "click", name: "点击登录", selector: "#login_submit" },
          {
            type: "waitForSelector",
            name: "等待签到按钮显示",
            selector: "#checkin",
            delay: 2000,
          },
          {
            type: "getText",
            name: "获取签到按钮文案",
            selector: "#checkin",
            saveAs: "checkinText",
          },
          {
            type: "evalClick",
            name: "点击签到",
            selector: "#checkin",
            delay: 2000,
            condition: {
              if: "checkinText",
              equals: "已签到",
              then: "break",
              else: "continue",
            },
          },
          {
            type: "getText",
            name: "获取签到按钮文案",
            selector: ".sign-use .one-line",
            saveAs: "signDayText",
            delay: 2000,
          },
        ],
        delay: 0,
        immediate: true,
      };

      let result = await httpRequest(
        "https://p2.660665.xyz/api/tasks",
        taskData,
      );

      if (result.result && result.result.success) {
        result.result.stepResults.forEach((item) => {
          if (item.step.name === "获取签到按钮文案") {
            if (item.data.text === "已签到") {
              console.log("任务执行成功: 今日已签到");
            } else {
              console.log("任务执行成功: 签到成功");
            }
          }
          if (item.step.name === "获取签到按钮文案") {
            console.log("已签到:", item.data.text);
          }
        });
      } else {
        console.log("任务执行失败:", result.error || "未知错误");
      }
    } catch (error) {
      console.error("Error sending task:", error);
    }
  }
}

!(async () => {
  if (!(await checkEnv())) return;
  console.log("====================\n");

  console.log("\n================== 签到 ==================");
  for (let user of userList) {
    await user.sign();
    await $.wait(200);
  }
})()
.catch((e) => $.logErr(e))
.finally(() => $.done());

// 检查变量
async function checkEnv() {
  if (userCookie) {
    console.log('userCookie:', userCookie, userCookie.split("@@"))
    for (let userCookies of userCookie.split("@@")) {
      if (userCookies)
        userList.push(
          new UserInfo({
            username: userCookies.split("#")[0],
            password: userCookies.split("#")[1],
          }),
        );
    }
    userCount = userList.length;
  } else {
    console.log("未找到wjkcCookie");
    return;
  }

  console.log(`共找到${userCount}个账号`);
  return true;
}

// 封装 HTTP 请求函数
async function httpRequest(url, taskData) {
  try {
    const response = await fetch(url, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(taskData),
    });
    return await response.json();
  } catch (error) {
    console.error("Problem with request:", error.message);
    throw error;
  }
}

